#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, M, K;
        scanf("%lld %lld %lld", &N, &M, &K);
        if (M * K >= N) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

